_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

  ret = 0;
  f0 = 2;
  dz.x = f0*(GP(vUv+hor) - GP(vUv-hor)).r;
  dz.y = f0*(GP(vUv+ver) - GP(vUv-ver)).r;

  blur = GetBlur1(vUv).r;
  k=blur.r*-6+1;

  ym=vUv.y-.5;
  dz = multiply(dz,mat2(cos(k),sin(k),-sin(k),cos(k)));
  if (sign(dz.y*ym)<0) {dz.y*=1-abs(ym)*4;}

  wi = 0.12;
  ret1 = -blur*wi + (1+wi)*GP(vUv+dz*.004).r;
  ret.r = max(0.8*GetBlur2(vUv).r,ret1)*0.99;
  ret.r -= clamp01(texture(sampler_noise_lq,vUv.x*0.05+uTime).r-q25) *abs(ym)*.2;


  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

 vec2 uv0 = vUvOriginal;
 vUv= (vUvOriginal-0.5)*uAspect.xy;
 rd = vec3 (vUv/zoom*vec2(1,torusdir),1);
 rd=RotXYZ(rd,scenerot);
 p  = camerapos + rd*RayMarch(camerapos,rd);
 pm = camerapos + rd*RayMarch2(camerapos,rd);

 norm = GetNormal(p);
 isLava = p.y>2;

 tmp3= p+vec3(torus1rad,0,0);
 side = sign(length(tmp3.xz)-torus1rad);

 float xlim =matan2 (tmp3.x, tmp3.z)*torus1rad;
 uv20.x = (xlim +scenepos)*texstr_x;
 uv20.y = (matan2(length(tmp3.xz)-torus1rad, -tmp3.y))*2/M_PI;

 tmp3= pm+ vec3(torus1rad,0,0);
 uv30.x = (matan2 (tmp3.x, tmp3.z)*torus1rad +scenepos)*texstr_x;
 uv30.y = (tmp3.y/2*compy/torus1dia);

 uv4 = 0.5 + (1.0 - abs( fract(uv20 * 0.25) * 2 - 1.0 )-.5);
 wall = makewall(uv4);
 isWindow = sat (2-50*wall.g)*(p.y<-1.2);

 diff.x = lum(wall-makewall(uv4+uTexSize.zw*vec2(1,0)))*!isWindow;
 diff.y = lum(wall-makewall(uv4+uTexSize.zw*vec2(0,1)))*!isWindow;

//tunnel lights
 rs = vec2(uv20.x*3,uv20.y)*M_PI;//* 3 = Synchron zur wall; besser waere (wg. abwechhslungsreicherer Spiegelung) KEINE Sync ?

 bel = elight(rs);
 wall = mix(wall, 0.2, sat(bel*4-2));

 lmod = mix((texture(sampler_pw_noise_lq,rs.x/512/M_PI+side/256).r>= .8-audioMidSmooth/4),
       sat(-1+2*costria((uv20.x+q5+side*1.5)/2/M_PI)), selmod);
 bel *= lmod;

//mirrored lights
 rs = vec2(uv30.x*3,uv30.y)*M_PI ;
 lmod = mix((texture(sampler_pw_noise_lq,rs.x/512/M_PI+side/256).r>= 0.8-audioMidSmooth/4),
        sat(-1+2*costria((uv20.x+q5+side*1.5)/2/M_PI)), selmod);

 vec3 mirbel = sat(elight(rs+diff*2)*2)*(norm.x==0)*(p.y>0);
 mirbel*=(wall+(fract(wall*3)))*lmod * exp(-abs(pm.z)*.03125);

//TEX
 tex = wall * sat (1-.0*abs(norm.y));
 tex = mix(tex*(4*bel+isLava*.1+.05*lavcol+0.02),1,bel>0.5) + mirbel ;


//LIGHTNING
 float lz = abs(1/rd.y);
 vec2 uv7 = vec2 (rd.x,1)*lz*vec2(0.02,0.005)-flpos;
 vec2 cld= (noise3(uv7.xy+wall.r*.05));
 vec3 l = normalize(flpos-p);
 float li0=0.07*sat(dot(norm,l));
 float li = f_intens*mix(li0,(.2/length(lz-flpos.z-cld*4))*(1-2*wall.b), isWindow);
 li *= !isLava;
 ret = tex + li*(wall+isWindow)*vec3 (0.5,0.6,1);

//Lava
 vec2 uvl = fract(uv20-.5);
 float ll = max(p.y>1,.3*!bridge*sat(pow(1*p.y-.38,2)));
 vec3 lav1 = mix(((GetBlur3(uvl)*0.75+GetPixel(uvl)).r),GetBlur3(vec2(uvl.x,0.5)).r*wall, !isLava);
 ret += ll*lav1*lavcol;


//PAINT
float sel = sat(4*tria(uv20.x*0.125)-2);
uv4 = 0.5 + (1.0 - abs( fract(uv20 * 0.25) * 2 - 1.0 )-.5); //already defined above !

uv4 = (uv4-.5)*texzoom+.5;
wtex[0]= 0;
wtex[1] = texture(rand01,uv4);
wtex[2] = texture(rand02,uv4);
wtex[3] = texture(rand03,uv4);
paint = mix(wtex[seltex1],wtex[seltex2]*tex1lum,sel);
ret += ((0.15+wall))*paint *sat(1-0.6*abs(norm.y))*sat(3-2*abs(p.y))*.75;

ret += abs(p.z) *fog * (1-isLava*.5) * slow_roam_cos; //NEBEL

ret.r += 2*sat(.0005/length(otria(uv20.xy-.5)) * (abs(uv20.y)<0.2)) * (tex1lum);

//ret -= sat(vRadius/2-.35);
//ret = GetPixel(uv0).r;

  fragColor = ret;
}
